export const getJsoDiffCase = (section: string, caseId: string): JsoDiffCase | undefined => {
  return jsoDiffCases.find((item) => item.section === section && item.caseId === caseId);
};

export const getJsoDiffCasesBySection = (section: string): JsoDiffCase[] => {
  return jsoDiffCases.filter((item) => item.section === section);
};
